on J1587Message 50 // 50 is Sender MID, can be dbNode name or MID
{
  dword count, i;
  J1587Param param;
  count = GetParameterCount(this);

  for (i = 0; i < count; i++) 
  {
    if (J1587GetParameter(this, param, i) == 0) 
    {
      write ("Parameter with PID %d received: %d", param.J1587_PID);
    }
  }
}
